// ── Yardımcı fonksiyonlar ───────────────────────────────────────────────
List<Soz> getSozByCategory(String cat) =>
    allSozler.where((s) => s.category == cat).toList();

List<Soz> searchSoz(String q) {
  final lower = q.toLowerCase();
  return allSozler.where((s) =>
    s.person.toLowerCase().contains(lower) ||
    s.quoteTurkish.toLowerCase().contains(lower) ||
    s.whatItSupports.toLowerCase().contains(lower) ||
    s.tags.any((t) => t.toLowerCase().contains(lower)),
  ).toList();
}

List<Soz> getRecommendedSoz() {
  const ids = ['SOZ-0001', 'SOZ-0101', 'SOZ-0201', 'SOZ-0301', 'SOZ-0401', 'SOZ-0501', 'SOZ-0601', 'SOZ-0701', 'SOZ-0801', 'SOZ-0901', 'SOZ-0050', 'SOZ-0150'];
  return ids
      .map((id) => allSozler.firstWhere(
        (s) => s.id == id,
        orElse: () => allSozler.first,
      ))
      .toList();
}
